#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=1e5+5;
int n,a[maxn],ans; 
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=n;i>=1;i--){
		a[i]=n/i*(n/i);
		for(int j=i<<1;j<=n;j+=i){
			a[i]-=a[j];
		}
		ans+=a[i]*i;
	}
	cout<<ans;
	return 0;
}
